  euclidean: "L2",
  manhattan: "L1",
  chebyshev: "L∞",
  minkowski3: "L3",
  minkowski05: "L½",
};

const METRIC_FORMULA: Record<Metric, string> = {
  euclidean: "sqrt(dx² + dy²)",
  manhattan: "dx + dy",
  chebyshev: "max(dx, dy)",
  minkowski3: "(dx³ + dy³)^(1/3)",
  minkowski05: "(sqrt(dx) + sqrt(dy))²",
};

const METRIC_INDEX: Record<Metric, number> = {
  euclidean: 0,
  manhattan: 1,
  chebyshev: 2,
  minkowski3: 3,
